#include <bits/stdc++.h>
using namespace std;
struct Twitter {
    map<int, vector<pair<int, int>>> tweets;
    map<int, set<int>> follows;
    int time;

    Twitter() {
        time = 0;
    }

    void postTweet(int userId, int tweetId) {
        time++;
        tweets[userId].emplace_back(time, tweetId);
    }

    vector<int> getNewsFeed(int userId) {
        vector<pair<int, int>> feed;
        if (tweets.find(userId) != tweets.end()) {
            feed.insert(feed.end(), tweets[userId].begin(), tweets[userId].end());
        }
        if (follows.find(userId) != follows.end()) {
            for (int followeeId : follows[userId]) {
                if (tweets.find(followeeId) != tweets.end()) {
                    feed.insert(feed.end(), tweets[followeeId].begin(), tweets[followeeId].end());
                }
            }
        }
        sort(feed.begin(), feed.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
            return a.first > b.first;
        });
        vector<int> result;
        for (int i = 0; i < 10 && i < feed.size(); i++) {
            result.push_back(feed[i].second);
        }
        return result;
    }

    void follow(int followerId, int followeeId) {
        follows[followerId].insert(followeeId);
    }

    void unfollow(int followerId, int followeeId) {
        if (follows.find(followerId) != follows.end() && follows[followerId].find(followeeId) != follows[followerId].end()) {
            follows[followerId].erase(followeeId);
        }
    }
};

